import itertools
import math

def naive_method(coin_probabilities, n):
    max_probability = 0
    best_combination = None
    for combination in itertools.combinations(coin_probabilities, n):
        probability = 1
        for p in combination:
            probability *= p
        for p in [q for q in coin_probabilities if q not in combination]:
            probability *= (1 - p)
        if probability > max_probability:
            max_probability = probability
            best_combination = combination
    return max_probability, best_combination

def greedy_method(coin_probabilities, n):
    sorted_probabilities = sorted(coin_probabilities, reverse=True)
    combination = sorted_probabilities[:n]
    probability = 1
    for p in combination:
        probability *= p
    for p in [q for q in coin_probabilities if q not in combination]:
        probability *= (1 - p)
    return probability, combination

def dp_method(coin_probabilities, n):
    dp = [[0.0 for _ in range(n + 1)] for _ in range(len(coin_probabilities) + 1)]
    for i in range(len(coin_probabilities) + 1):
        dp[i][0] = 1.0
    for i in range(1, len(coin_probabilities) + 1):
        for j in range(1, min(i, n) + 1):
            dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - 1] * coin_probabilities[i - 1])
    combination = []
    i, j = len(coin_probabilities), n
    while j > 0:
        if dp[i][j] != dp[i - 1][j]:
            combination.append(coin_probabilities[i - 1])
            j -= 1
        i -= 1
    probability = dp[len(coin_probabilities)][n]
    return probability, combination

