def calculate_probability_dp(coins, n):
    dp = [[0.0] * (n + 1) for _ in range(len(coins) + 1)]
    dp[0][0] = 1.0
    for i in range(1, len(coins) + 1):
        for j in range(n + 1):
            if j == 0:
                dp[i][j] = (1 - coins[i - 1][0]) * dp[i - 1][j]
            else:
                dp[i][j] = coins[i - 1][0] * dp[i - 1][j - 1] + (1 - coins[i - 1][0]) * dp[i - 1][j]
    max_prob = 0
    best_set = None
    for i in range(len(coins) + 1):
        if dp[i][n] > max_prob:
            max_prob = dp[i][n]
            best_set = coins[:i]
    return best_set, max_prob

