def generate_powerset(set_of_elements):
    powerset = set()
    num_elements = len(set_of_elements)
    for i in range(2**num_elements):
        subset = set()
        binary = bin(i)[2:].zfill(num_elements)
        for j in range(num_elements):
            if binary[j] == '1':
                subset.add(list(set_of_elements)[j])
