def calculate_n():
    n = 0
    while True:
        yield n
        n += 1

def fibonacci_sequence():
    a, b = 0, 1
    while True:
        yield a
        a, b = b, a + b

def generate_primes():
    primes = []
    num = 2
    while True:
        is_prime = True
        for prime in primes:
            if num % prime == 0:
                is_prime = False
                break
        if is_prime:
            primes.append(num)
            yield num
        num += 1

def generate_perfect_squares():
    n = 1
    while True:
        yield n * n
        n += 1

def generate_catalan_numbers():
    catalan = [1]
    for i in range(1, 1000):
        catalan.append((4 * i - 2) * catalan[i - 1] // (i + 1))
        yield catalan[i]

